37	const PROCESSING_FEE = 5;
38	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
39	const BUILDING_BLOCK_PREMIUM = 60;
40	const BUILDING_BLOCK_SIZE = 3;
41	const CURSED_SURCHARGE_RATE = 0.5;
42	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
43	const HIGH_ENCHANTMENT_THRESHOLD = 5;
44	const LOYALTY_DISCOUNT_RATE = 0.2;
45	const LOYALTY_YEARS_THRESHOLD = 2;
46	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
47	
48	const BASE_PREMIUMS: Record<string, number> = {
49	  sword: 100,
50	  amulet: 60,
51	  staff: 80,
52	  potion: 40,
53	  rune: 25,
54	};
55	
56	const INSURANCE_VALUES: Record<string, number> = {
57	  sword: 1000,
58	  amulet: 600,
59	  staff: 800,
60	  potion: 400,
61	};
62	
63	const DEDUCTIBLE = 100;
64	const CAP_MULTIPLIER = 2;
65	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
66	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
67	
68	const groupItemsByType = (items: Item[]): Record<string, Item[]> => {
69	  const groups: Record<string, Item[]> = {};
70	  for (const item of items) {
71	    if (!groups[item.type]) {
72	      groups[item.type] = [];
73	    }
74	    groups[item.type].push(item);
75	  }
76	  return groups;
77	};
78	
79	const calculateSingleItemPremium = (item: Item): number => {
80	  const basePremium = BASE_PREMIUMS[item.type];
81	  const cursedSurcharge = item.cursed ? basePremium * CURSED_SURCHARGE_RATE : 0;
82	  const enchantmentSurcharge =
83	    item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
84	      ? basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE
85	      : 0;
86	  return basePremium + cursedSurcharge + enchantmentSurcharge;
87	};
88	
89	const calculateGroupPremium = (typeItems: Item[]): { total: number; base: number } => {
90	  if (typeItems.length === BUILDING_BLOCK_SIZE) {
91	    return { total: BUILDING_BLOCK_PREMIUM, base: BUILDING_BLOCK_PREMIUM };
92	  }
93	  return typeItems.reduce(
94	    (acc, item) => ({
95	      total: acc.total + calculateSingleItemPremium(item),
96	      base: acc.base + BASE_PREMIUMS[item.type],
97	    }),
98	    { total: 0, base: 0 },
99	  );
100	};
101	
102	const calculateItemsPremium = (items: Item[]): { total: number; base: number } => {
103	  const groups = Object.values(groupItemsByType(items));
104	  return groups.reduce(
105	    (acc, group) => {
106	      const groupResult = calculateGroupPremium(group);
107	      return { total: acc.total + groupResult.total, base: acc.base + groupResult.base };
108	    },
109	    { total: 0, base: 0 },
110	  );
111	};
112	
113	const calculateStepPremium = (
114	  step: Step,
115	  customerYears: number,
116	  isFollowUp: boolean,
117	): number => {
118	  const { total: itemsPremium, base: policyBasePremium } = calculateItemsPremium(step.items ?? []);
119	  const surcharge = policyBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
120	  const loyaltyDiscount =
121	    customerYears >= LOYALTY_YEARS_THRESHOLD
122	      ? policyBasePremium * LOYALTY_DISCOUNT_RATE
123	      : 0;
124	  const followUpDiscount = isFollowUp ? policyBasePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
125	  return Math.ceil(itemsPremium + surcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
126	};
127	
128	const calculateDamagePayout = (
129	  damage: { itemType: string; amount: number },
130	  policyItems: Item[],
131	): number => {
132	  const matchingItem = policyItems.find((item) => item.type === damage.itemType);
133	  const enchantment = matchingItem?.enchantment ?? 0;
134	  const reimbursement = enchantment >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD
135	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
136	    : damage.amount;
137	  return reimbursement - DEDUCTIBLE;
138	};
