140	const calculateClaimResult = (step: Step, policyStep: Step): ClaimResult => {
141	  const policyItems = policyStep.items ?? [];
142	  const insuranceSum = policyItems.reduce(
143	    (sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0),
144	    0,
